package com.babidndn.order;
import com.fasterxml.jackson.annotation.JsonIgnore;import jakarta.persistence.*;
@Entity public class OrderItem { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id; @ManyToOne(optional=false) @JsonIgnore private CustomerOrder order; private Long menuId; private String menuName; private int unitPrice; private int quantity; private String optionSummary; private int optionPrice; protected OrderItem(){} public OrderItem(Long menuId,String menuName,int unitPrice,int quantity,String optionSummary,int optionPrice){this.menuId=menuId;this.menuName=menuName;this.unitPrice=unitPrice;this.quantity=quantity;this.optionSummary=optionSummary;this.optionPrice=optionPrice;} public Long getId(){return id;} public Long getMenuId(){return menuId;} public String getMenuName(){return menuName;} public int getUnitPrice(){return unitPrice;} public int getQuantity(){return quantity;} public String getOptionSummary(){return optionSummary;} public int getOptionPrice(){return optionPrice;} public int getLineTotal(){return (unitPrice+optionPrice)*quantity;} void setOrder(CustomerOrder order){this.order=order;} }
